import React, { useState, useEffect } from 'react';
import { Bar, Line } from 'react-chartjs-2';
import {
Chart as ChartJS,
CategoryScale,
LinearScale,
BarElement,
LineElement,
PointElement,
Title,
Tooltip,
Legend,
} from 'chart.js';
import WebSocketService from '../services/WebSocketService';

ChartJS.register(
CategoryScale,
LinearScale,
BarElement,
LineElement,
PointElement,
Title,
Tooltip,
Legend
);

const Charts = () => {
const [vehicleStatusData, setVehicleStatusData] = useState({
labels: ['Active', 'Idle', 'Maintenance', 'Offline'],
datasets: [
{
label: 'Vehicle Status',
data: [10, 5, 3, 2], // Sample data
backgroundColor: ['#3B82F6', '#FBBF24', '#EF4444', '#6B7280'],
borderColor: ['#1E40AF', '#D97706', '#B91C1C', '#4B5563'],
borderWidth: 1,
},
],
});

const [fuelEfficiencyData, setFuelEfficiencyData] = useState({
labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
datasets: [
{
label: 'Fuel Efficiency (mpg)',
data: [25, 27, 26, 28, 30, 29], // Sample data
fill: false,
borderColor: '#3B82F6',
tension: 0.1,
},
],
});

useEffect(() => {
WebSocketService.connect();

```
WebSocketService.subscribe('/topic/vehicles', (message) => {
  const vehicleData = JSON.parse(message.body);

  const newStatusData = {
    ...vehicleStatusData,
    datasets: [
      {
        ...vehicleStatusData.datasets[0],
        data: [
          vehicleData.filter((v) => v.status === 'ACTIVE').length,
          vehicleData.filter((v) => v.status === 'IDLE').length,
          vehicleData.filter((v) => v.status === 'MAINTENANCE').length,
          vehicleData.filter((v) => v.status === 'OFFLINE').length,
        ],
      },
    ],
  };
  setVehicleStatusData(newStatusData);
});

return () => {
  WebSocketService.disconnect();
};
