},
y: {
ticks: { color: '#1F2937' },
grid: { color: '#E5E7EB' },
},
},
};

return ( <div className="grid grid-cols-1 md:grid-cols-2 gap-6"> <div className="stat-card"> <h2 className="text-lg font-semibold mb-4">Vehicle Status</h2> <div className="h-64">
<Bar
data={vehicleStatusData}
options={{
...chartOptions,
plugins: {
...chartOptions.plugins,
title: {
...chartOptions.plugins.title,
text: 'Vehicle Status Distribution',
},
},
}}
/> </div> </div> <div className="stat-card"> <h2 className="text-lg font-semibold mb-4">Fuel Efficiency</h2> <div className="h-64">
<Line
data={fuelEfficiencyData}
options={{
...chartOptions,
plugins: {
...chartOptions.plugins,
title: {
...chartOptions.plugins.title,
text: 'Fuel Efficiency Over Time',
},
},
}}
/> </div> </div> </div>
);
};

export default Charts;
